262	fn jj_rev_exists(repo: &str, cwd: &std::path::Path, rev: &str) -> Result<(), String> {
263	    run(
264	        "jj",
265	        &["log", "-r", rev, "--no-graph", "-T", "\"x\"", "-R", repo],
266	        cwd,
267	    )
268	    .map_err(|e| e.to_string())?;
269	    Ok(())
270	}
