272	/// Log what finalize is about to do so the user sees the plan before detach.
273	fn log_plan(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
274	    let repo_str = opts.repo.to_string_lossy();
275	    let cwd = std::path::Path::new(".");
276	
277	    if let Some(ref sq) = opts.squash {
278	        info!(
279	            "finalize: squash {} → {} in {}",
280	            sq.source, sq.target, repo_str
281	        );
282	    }
283	    if let Some(ref bookmark) = opts.bookmark {
284	        let target_rev = opts
285	            .squash
286	            .as_ref()
287	            .map(|sq| sq.target.as_str())
288	            .unwrap_or("@"); // OK: same as above
289	        let current = jj_rev_short(&repo_str, cwd, bookmark).unwrap_or_else(|_| "?".into()); // OK: logging only — fall back to "?" if revset fails
290	        let target = jj_rev_short(&repo_str, cwd, target_rev).unwrap_or_else(|_| "?".into()); // OK: same
291	        info!("finalize: set bookmark '{bookmark}' {current} → {target} ({target_rev})");
292	        if opts.push {
293	            info!("finalize: push '{bookmark}' to remote");
294	        }
295	    }
296	
297	    Ok(())
298	}
