300	/// Short one-line summary of a revset: `<change_short> <commit_short>`.
301	fn jj_rev_short(repo: &str, cwd: &std::path::Path, rev: &str) -> Result<String, String> {
302	    run(
303	        "jj",
304	        &[
305	            "log",
306	            "-r",
307	            rev,
308	            "--no-graph",
309	            "-T",
310	            "change_id.shortest(8) ++ \" \" ++ commit_id.shortest(8)",
311	            "-R",
