319	fn finalize_exec(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
320	    debug!("finalize_exec: starting opts={opts:?}");
321	    let repo_str = opts.repo.to_string_lossy();
322	    let cwd = std::path::Path::new(".");
323	
324	    // Squash if requested
325	    if let Some(ref sq) = opts.squash {
326	        let delay = std::time::Duration::from_secs_f64(opts.delay_secs);
327	        debug!("finalize_exec: sleeping {delay:?}");
328	        std::thread::sleep(delay);
329	
330	        info!("finalize: squashing {} → {}...", sq.source, sq.target);
331	        run(
332	            "jj",
333	            &[
334	                "squash",
335	                "--ignore-immutable",
336	                "--use-destination-message",
337	                "--from",
338	                &sq.source,
339	                "--into",
340	                &sq.target,
341	                "-R",
342	                &repo_str,
343	            ],
344	            cwd,
345	        )?;
346	    }
347	
348	    // Set bookmark and push if requested
349	    if let Some(ref bookmark) = opts.bookmark {
350	        // Verify bookmark exists — don't silently create new ones
351	        let result = run("jj", &["bookmark", "list", bookmark, "-R", &repo_str], cwd)?;
352	        if result.is_empty() {
353	            return Err(format!("bookmark '{bookmark}' does not exist").into());
354	        }
355	
356	        let rev = opts
357	            .squash
358	            .as_ref()
359	            .map(|sq| sq.target.as_str())
360	            .unwrap_or("@"); // OK: no squash spec → bookmark points at current @
361	        info!("finalize: setting bookmark '{bookmark}' to {rev}...");
362	        run(
363	            "jj",
364	            &["bookmark", "set", bookmark, "-r", rev, "-R", &repo_str],
365	            cwd,
366	        )?;
367	
368	        if opts.push {
369	            info!("finalize: pushing '{bookmark}' to origin...");
370	            run(
371	                "jj",
372	                &["git", "push", "--bookmark", bookmark, "-R", &repo_str],
373	                &opts.repo,
374	            )?;
375	        }
376	    }
377	
378	    info!("finalize: done");
379	    debug!("finalize_exec: done");
380	    Ok(())
381	}
