383	pub fn build_exec_args(opts: &FinalizeOpts) -> Vec<String> {
384	    let mut args = vec![
385	        "finalize".to_string(),
386	        "--exec".to_string(),
387	        "--repo".to_string(),
388	        opts.repo.to_string_lossy().to_string(),
389	    ];
