407	/// Spawn a detached child process with `--exec` and return immediately.
408	/// The child re-enters `main()`, parses `--exec`, and `finalize()` routes
409	/// it to `finalize_exec()` where the actual work happens.
410	fn detach(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
411	    debug!("detach: parent starting opts={opts:?}");
412	
413	    let exe = std::env::current_exe()?;
414	    let args = build_exec_args(opts);
415	    debug!("detach: exe={exe:?} args={args:?}");
416	
417	    let mut cmd = std::process::Command::new(exe);
418	    cmd.args(&args).stdin(Stdio::null());
419	
420	    // Hand the child the user's controlling terminal when one exists so
421	    // its output stays visible after the parent exits. Inherited pipes
422	    // are unreliable here — the bash-tool / cron caller typically closes
423	    // its read end on parent exit, silently dropping child writes. Fall
424	    // back to null when there is no tty (pipe-invoked / CI / Windows);
425	    // the log file is authoritative in that case.
426	    match std::fs::OpenOptions::new()
427	        .read(true)
428	        .write(true)
429	        .open("/dev/tty")
430	    {
431	        Ok(tty) => {
432	            debug!("detach: /dev/tty opened, child output → terminal");
433	            let out = tty.try_clone()?;
434	            cmd.stdout(Stdio::from(out));
435	            cmd.stderr(Stdio::from(tty));
436	        }
437	        Err(e) => {
438	            debug!("detach: /dev/tty unavailable ({e}), child output → null");
439	            cmd.stdout(Stdio::null());
440	            cmd.stderr(Stdio::null());
441	        }
442	    }
443	
444	    #[cfg(unix)]
445	    {
446	        use std::os::unix::process::CommandExt;
447	        unsafe {
448	            cmd.pre_exec(|| {
449	                libc::setsid();
450	                Ok(())
451	            });
452	        }
453	    }
454	
455	    let child = cmd.spawn()?;
456	    debug!("detach: spawned child pid={}", child.id());
457	    match &opts.log {
458	        Some(log) => info!(
459	            "finalize: detached (pid {}), log: {}",
460	            child.id(),
461	            log.display()
462	        ),
463	        None => info!("finalize: detached (pid {})", child.id()),
464	    }
465	    Ok(())
466	}
467	
468	pub fn finalize(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
469	    // Nothing to do — show help hint
470	    if opts.squash.is_none() && !opts.push {
471	        return Err("nothing to do (see --help for options)".into());
472	    }
473	
474	    debug!("finalize: entry opts={opts:?}");
475	
476	    // Validate synchronously before detaching so failures exit with a
477	    // visible non-zero status rather than hiding in the detached child's log.
478	    // Skip in --exec (the re-entered child already passed preflight in the parent).
479	    if !opts.exec {
480	        preflight(opts)?;
481	    }
482	
483	    let result = if opts.detach && !opts.exec {
484	        detach(opts)
485	    } else {
486	        finalize_exec(opts)
487	    };
488	    match &result {
489	        Ok(()) => debug!("finalize: exit ok"),
490	        Err(e) => {
491	            debug!("finalize: exit err={e}");
492	            // In the detached-child path the caller can't observe our
493	            // non-zero exit. Drop a failure marker so a later vc-x1
494	            // invocation can surface the problem.
495	            if opts.exec {
496	                write_failure_marker(opts, &e.to_string());
497	            }
498	        }
499	    }
500	    result
501	}
